import React from 'react';
import { Button } from '@codegouvfr/react-dsfr/Button';

interface FeedbackProps {
  isCorrect: boolean;
  /** Texte optionnel à afficher (ex: la bonne réponse) */
  detail?: string;
  /** Appelé quand l'utilisateur clique sur "Suivant" */
  onNext: () => void;
}

/**
 * Retour visuel après une réponse : vert si correct, rouge sinon.
 * Affiche un message encourageant et un bouton pour passer à la suite.
 */
export function Feedback({ isCorrect, detail, onNext }: FeedbackProps): React.ReactElement {
  return (
    <div className={`feedback ${isCorrect ? 'feedback-correct' : 'feedback-incorrect'}`}>
      <div className="feedback-text">
        {isCorrect ? 'Bravo ! 🎉' : 'Essaie encore ! 💪'}
      </div>
      {detail && <div style={{ marginBottom: 12 }}>{detail}</div>}
      <Button priority="primary" iconId="fr-icon-arrow-right-line" iconPosition="right" onClick={onNext}>
        Suivant
      </Button>
    </div>
  );
}
