import React from 'react';

interface SoundBoxesProps {
  /** Nombre total de cases (= nombre de sons dans le mot) */
  totalBoxes: number;
  /** Sons déjà placés par l'enfant */
  placedSounds: string[];
  /** Sons corrects (pour l'affichage après validation) */
  correctSounds: string[];
  /** null = en cours, true/false = répondu */
  isCorrect: boolean | null;
}

/**
 * Cases de phonèmes sous le mot.
 * Chaque case affiche le son placé par l'enfant ou reste vide.
 * Après validation : les cases correctes sont vertes, les incorrectes rouges.
 */
export function SoundBoxes({
  totalBoxes,
  placedSounds,
  correctSounds,
  isCorrect,
}: SoundBoxesProps): React.ReactElement {
  const boxes = Array.from({ length: totalBoxes }, (_, i) => i);

  return (
    <div className="sound-boxes-row">
      {boxes.map((i) => {
        const placed = placedSounds[i] || '';
        const isBoxCorrect = isCorrect !== null && placed === correctSounds[i];
        const isBoxWrong = isCorrect !== null && placed !== '' && placed !== correctSounds[i];

        /* Style conditionnel après validation */
        const style: React.CSSProperties = {};
        if (isBoxCorrect) {
          style.borderColor = '#27AE60';
          style.background = '#E8F5E9';
        } else if (isBoxWrong) {
          style.borderColor = '#E74C3C';
          style.background = '#FFEBEE';
        }

        return (
          <div key={i} className={`sound-box ${placed ? 'sound-box-filled' : ''}`} style={style}>
            {placed || ''}
          </div>
        );
      })}
    </div>
  );
}
