import React from 'react';
import { Card } from '@codegouvfr/react-dsfr/Card';
import { NavigationItem } from '../data/navigation';

interface ThemeCardProps {
  item: NavigationItem;
}

/**
 * Carte cliquable pour naviguer vers un thème, sous-thème ou exercice.
 * Utilise le composant Card du DSFR.
 */
export function ThemeCard({ item }: ThemeCardProps): React.ReactElement {
  return (
    <Card
      title={item.label}
      desc={item.description}
      start={item.icon ? <span style={{ fontSize: '1.5rem' }}>{item.icon}</span> : undefined}
      enlargeLink
      linkProps={{ to: item.path }}
      grey={false}
      border
      classes={{ root: 'theme-card-dsfr' }}
    />
  );
}
