import React, { useState, useCallback } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { NumPad } from '../../../components/exercises/NumPad';
import { AnalogClock } from '../../../components/sciences/AnalogClock';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useLireHeure, type LireHeureMode } from './useLireHeure';

const BACK = '/sciences';

const MODE_LABELS: Record<LireHeureMode, string> = {
  hour: 'Heure seule',
  minutes: 'Minutes',
  full: 'Heure + minutes',
};

/** Lire l’heure sur un cadran : saisie au pavé numérique (heures 1–12, minutes 0–59). */
export function LireHeure(): React.ReactElement {
  const {
    mode,
    setMode,
    question,
    hourInput,
    minuteInput,
    setHourInput,
    setMinuteInput,
    activeField,
    setActiveField,
    padValue,
    setPadValue,
    feedback,
    check,
    next,
    hideMinuteHand,
  } = useLireHeure();
  const { wrapNext } = useExerciseAnswerLimit(BACK);
  const [incompleteHint, setIncompleteHint] = useState<string | null>(null);

  const handleCheck = useCallback(() => {
    setIncompleteHint(null);
    const r = check();
    if (r === 'incomplete') {
      setIncompleteHint(
        mode === 'minutes'
          ? 'Écris les minutes (nombre sur le cadran).'
          : mode === 'hour'
            ? 'Écris l’heure (1 à 12).'
            : 'Écris l’heure et les minutes.'
      );
    }
  }, [check, mode]);

  const onFeedbackNext = useCallback(() => {
    setIncompleteHint(null);
    wrapNext(next);
  }, [wrapNext, next]);

  const solutionText =
    question.mode === 'minutes'
      ? `${question.minute} min`
      : question.mode === 'hour'
        ? `${question.hour12} h`
        : `${question.hour12} h ${String(question.minute).padStart(2, '0')}`;

  return (
    <ExerciseWrapper title="Lire l’heure" backPath={BACK}>
      <p className="sciences-hint">
        Heures en <strong>1 à 12</strong> (cadran). Minutes en <strong>0 à 59</strong>. En mode « Minutes », l’heure est
        indiquée sous le cadran (3 h).
      </p>

      <div className="sciences-clock-modes" role="tablist" aria-label="Mode">
        {(['hour', 'minutes', 'full'] as const).map((m) => (
          <button
            key={m}
            type="button"
            className={`pendu-pill ${mode === m ? 'pendu-pill-active' : ''}`}
            onClick={() => setMode(m)}
          >
            {MODE_LABELS[m]}
          </button>
        ))}
      </div>

      <div className="sciences-clock-wrap">
        <AnalogClock
          hour12={question.hour12}
          minute={question.minute}
          hideMinuteHand={hideMinuteHand}
        />
        {question.mode === 'minutes' && (
          <p className="sciences-clock-fixed-hour">On est après 3 h (regarde seulement les minutes).</p>
        )}
      </div>

      {feedback === null ? (
        <>
          <div className="sciences-clock-inputs">
            {(mode === 'hour' || mode === 'full') && (
              <label className="sciences-clock-field">
                <span>Heure (1–12)</span>
                <input
                  type="text"
                  inputMode="numeric"
                  className={`sciences-clock-inp ${activeField === 'hour' ? 'sciences-clock-inp-active' : ''}`}
                  value={hourInput}
                  onChange={(e) => setHourInput(e.target.value)}
                  onFocus={() => setActiveField('hour')}
                  placeholder="?"
                  aria-label="Heure"
                />
              </label>
            )}
            {(mode === 'minutes' || mode === 'full') && (
              <label className="sciences-clock-field">
                <span>Minutes (0–59)</span>
                <input
                  type="text"
                  inputMode="numeric"
                  className={`sciences-clock-inp ${activeField === 'minute' ? 'sciences-clock-inp-active' : ''}`}
                  value={minuteInput}
                  onChange={(e) => setMinuteInput(e.target.value)}
                  onFocus={() => setActiveField('minute')}
                  placeholder="?"
                  aria-label="Minutes"
                />
              </label>
            )}
          </div>
          {incompleteHint && <p className="transformation-incomplete-hint">{incompleteHint}</p>}
          <NumPad value={padValue} onChange={setPadValue} onValidate={handleCheck} />
          <button type="button" className="transformation-verify-btn feedback-next" onClick={handleCheck}>
            Vérifier
          </button>
        </>
      ) : (
        <Feedback
          isCorrect={feedback}
          detail={feedback ? `C’était : ${solutionText}` : `La bonne réponse était : ${solutionText}`}
          onNext={onFeedbackNext}
        />
      )}
    </ExerciseWrapper>
  );
}
