import { useState, useCallback, useMemo, useEffect } from 'react';
import { useScore } from '../../../hooks/useScore';
import type { PenduGameLevel, PenduThemeId, PenduWordEntry } from '../../../data/pendu-words';
import {
  getPenduWordPool,
  pickRandomPenduWord,
  penduMaxErrors,
  penduNormalizeLetter,
  penduWordLetterBases,
} from '../../../data/pendu-words';

export type PenduPlayStatus = 'playing' | 'won' | 'lost';

export interface UsePenduReturn {
  gameLevel: PenduGameLevel;
  setGameLevel: (l: PenduGameLevel) => void;
  theme: PenduThemeId | 'tous';
  setTheme: (t: PenduThemeId | 'tous') => void;
  pool: PenduWordEntry[];
  current: PenduWordEntry | null;
  word: string;
  guessedBases: Set<string>;
  wrongCount: number;
  maxErrors: number;
  status: PenduPlayStatus;
  guessLetter: (letter: string) => void;
  /** Révèle une lettre non encore trouvée (toujours autorisé tant qu’il reste des lettres). */
  useLetterHint: () => void;
  letterHintAvailable: boolean;
  /** Indices textuels déjà affichés pour le mot en cours (0 à 3). */
  textHintsRevealed: number;
  revealedTextHints: string[];
  /** Affiche le prochain indice textuel (max 3 par mot). */
  useTextHint: () => void;
  textHintAvailable: boolean;
  nextWord: () => void;
  isLetterUsed: (letter: string) => boolean;
  isSlotRevealed: (index: number, char: string) => boolean;
}

export function usePendu(): UsePenduReturn {
  const { addPoint, removePoint } = useScore();
  const [gameLevel, setGameLevel] = useState<PenduGameLevel>(1);
  const [theme, setTheme] = useState<PenduThemeId | 'tous'>('tous');

  const pool = useMemo(() => getPenduWordPool(theme, gameLevel), [theme, gameLevel]);

  const [current, setCurrent] = useState<PenduWordEntry | null>(null);
  const [guessedBases, setGuessedBases] = useState<Set<string>>(() => new Set());
  const [wrongCount, setWrongCount] = useState(0);
  const [status, setStatus] = useState<PenduPlayStatus>('playing');
  const [textHintsRevealed, setTextHintsRevealed] = useState(0);

  const maxErrors = penduMaxErrors(gameLevel);

  const word = current?.w ?? '';

  const unrevealedLetterCount = useMemo(() => {
    if (!word) return 0;
    return Array.from(word).filter(
      (ch) => !/[\s'-]/.test(ch) && !guessedBases.has(penduNormalizeLetter(ch))
    ).length;
  }, [word, guessedBases]);

  const letterHintAvailable = status === 'playing' && unrevealedLetterCount > 0;
  const textHintAvailable = status === 'playing' && textHintsRevealed < 3 && Boolean(current);

  const revealedTextHints = useMemo(() => {
    if (!current || textHintsRevealed === 0) return [];
    return current.hints.slice(0, textHintsRevealed);
  }, [current, textHintsRevealed]);

  const startNewWord = useCallback(
    (excludePrev: string) => {
      if (pool.length === 0) {
        setCurrent(null);
        return;
      }
      const next =
        pickRandomPenduWord(pool, excludePrev ? excludePrev.toLowerCase() : undefined) ?? pool[0];
      setCurrent(next ?? null);
      setGuessedBases(new Set());
      setWrongCount(0);
      setStatus('playing');
      setTextHintsRevealed(0);
    },
    [pool]
  );

  useEffect(() => {
    if (pool.length === 0) {
      setCurrent(null);
      return;
    }
    if (!current || !pool.some((e) => e.w === current.w)) {
      startNewWord(current?.w ?? '');
    }
  }, [pool, current, startNewWord]);

  const checkWinAfterGuess = useCallback((bases: Set<string>, w: string) => {
    const needed = penduWordLetterBases(w);
    return Array.from(needed).every((b) => bases.has(b));
  }, []);

  const guessLetter = useCallback(
    (letter: string) => {
      if (status !== 'playing' || !word) return;
      const base = penduNormalizeLetter(letter);
      if (!base || guessedBases.has(base)) return;

      const hasInWord = Array.from(word).some(
        (ch) => !/[\s'-]/.test(ch) && penduNormalizeLetter(ch) === base
      );

      const nextBases = new Set(guessedBases).add(base);
      setGuessedBases(nextBases);

      if (!hasInWord) {
        setWrongCount((w) => {
          const nw = w + 1;
          if (nw >= maxErrors) {
            setStatus('lost');
            removePoint();
          }
          return nw;
        });
      }

      if (checkWinAfterGuess(nextBases, word)) {
        setStatus('won');
        addPoint();
      }
    },
    [
      status,
      word,
      guessedBases,
      maxErrors,
      checkWinAfterGuess,
      addPoint,
      removePoint,
    ]
  );

  const useLetterHint = useCallback(() => {
    if (status !== 'playing' || !word) return;

    const unrevealed = Array.from(word)
      .map((ch, i) => ({ ch, i }))
      .filter(
        ({ ch }) =>
          !/[\s'-]/.test(ch) && !guessedBases.has(penduNormalizeLetter(ch))
      );

    if (unrevealed.length === 0) return;

    const pick = unrevealed[Math.floor(Math.random() * unrevealed.length)];
    const base = penduNormalizeLetter(pick.ch);
    const nextBases = new Set(guessedBases).add(base);
    setGuessedBases(nextBases);

    if (checkWinAfterGuess(nextBases, word)) {
      setStatus('won');
      addPoint();
    }
  }, [
    status,
    word,
    guessedBases,
    checkWinAfterGuess,
    addPoint,
  ]);

  const useTextHint = useCallback(() => {
    if (!textHintAvailable || !current) return;
    setTextHintsRevealed((n) => Math.min(3, n + 1));
  }, [textHintAvailable, current]);

  const nextWord = useCallback(() => {
    startNewWord(word);
  }, [word, startNewWord]);

  const isLetterUsed = useCallback(
    (letter: string) => guessedBases.has(penduNormalizeLetter(letter)),
    [guessedBases]
  );

  const isSlotRevealed = useCallback(
    (_index: number, char: string) => {
      if (/[\s'-]/.test(char)) return true;
      return guessedBases.has(penduNormalizeLetter(char));
    },
    [guessedBases]
  );

  return {
    gameLevel,
    setGameLevel,
    theme,
    setTheme,
    pool,
    current,
    word,
    guessedBases,
    wrongCount,
    maxErrors,
    status,
    guessLetter,
    useLetterHint,
    letterHintAvailable,
    textHintsRevealed,
    revealedTextHints,
    useTextHint,
    textHintAvailable,
    nextWord,
    isLetterUsed,
    isSlotRevealed,
  };
}
