import React, { useState, useCallback } from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useScore } from '../../../hooks/useScore';
import { pickElectriciteQuestion, type ElectriciteQuestion } from '../../../data/sciences-electricite';

const BACK = '/sciences';

/** Quiz électricité : sécurité et conducteurs / isolants. */
export function ElectriciteJeu(): React.ReactElement {
  const { addPoint, removePoint } = useScore();
  const { wrapNext } = useExerciseAnswerLimit(BACK);
  const [current, setCurrent] = useState<ElectriciteQuestion>(() => pickElectriciteQuestion());
  const [feedback, setFeedback] = useState<boolean | null>(null);
  const [explain, setExplain] = useState<string | null>(null);

  const nextRound = useCallback(() => {
    setCurrent((c) => pickElectriciteQuestion(c.id));
    setFeedback(null);
    setExplain(null);
  }, []);

  const handleChoice = useCallback(
    (choiceId: string) => {
      if (feedback !== null) return;
      const ok = choiceId === current.correctId;
      setFeedback(ok);
      setExplain(current.explain);
      if (ok) addPoint();
      else removePoint();
    },
    [feedback, current, addPoint, removePoint]
  );

  const onFeedbackNext = useCallback(() => {
    wrapNext(nextRound);
  }, [wrapNext, nextRound]);

  return (
    <ExerciseWrapper title="Électricité" backPath={BACK}>
      <p className="sciences-hint">
        Réfléchis bien : sécurité d’abord. Si tu hésites, demande à un adulte dans la vraie vie.
      </p>

      {feedback === null ? (
        <>
          <div className="sciences-elec-prompt" role="heading" aria-level={2}>
            {current.prompt}
          </div>
          <div className="sciences-elec-choices" role="group">
            {current.choices.map((ch) => (
              <button
                key={ch.id}
                type="button"
                className="sciences-elec-btn"
                onClick={() => handleChoice(ch.id)}
              >
                {ch.label}
              </button>
            ))}
          </div>
        </>
      ) : (
        <Feedback
          isCorrect={feedback}
          detail={explain ?? undefined}
          onNext={onFeedbackNext}
        />
      )}
    </ExerciseWrapper>
  );
}
