import React from 'react';
import { SubjectList } from '../../../components/SubjectList';
import { filterGeometrieForGrade } from '../../../data/navFilter';
import { useSchoolYear } from '../../../hooks/useSchoolYear';

/** Page de listing des exercices de Géométrie */
export function GeometrieHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterGeometrieForGrade(grade);
  return <SubjectList title="Géométrie" items={items} backPath="/maths" />;
}
