import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { shuffleArray } from '../../../utils/shuffleArray';
import { useScore } from '../../../hooks/useScore';
import { SHAPES, SHAPE_COLORS, ShapeDefinition } from '../../../data/formes';

/** Une forme placée dans la grille avec un ID unique */
interface PlacedShape {
  uid: number;
  shape: ShapeDefinition;
  color: string;
  rotation: number;
}

interface UseTrouveFormesReturn {
  /** Forme cible à trouver (ex: "Carré") */
  targetName: string;
  /** Grille de formes affichées */
  grid: PlacedShape[];
  /** IDs des formes sélectionnées par l'enfant */
  selectedIds: Set<number>;
  /** Sélectionner/désélectionner une forme */
  toggleShape: (uid: number) => void;
  /** Vérifier la sélection */
  check: () => void;
  isCorrect: boolean | null;
  next: () => void;
}

/** Génère une grille de 8 formes avec 2-4 occurrences de la cible */
function generateGrid(): { targetShape: ShapeDefinition; grid: PlacedShape[] } {
  const targetShape = SHAPES[randomInRange(0, SHAPES.length - 1)];
  const targetCount = randomInRange(2, 4);
  const otherShapes = SHAPES.filter((s) => s.id !== targetShape.id);

  const items: PlacedShape[] = [];
  let uid = 0;

  /* Ajoute les formes cibles */
  for (let i = 0; i < targetCount; i++) {
    items.push({
      uid: uid++,
      shape: targetShape,
      color: SHAPE_COLORS[randomInRange(0, SHAPE_COLORS.length - 1)],
      rotation: randomInRange(0, 3) * 45,
    });
  }

  /* Remplit le reste avec des formes aléatoires différentes */
  const remaining = 8 - targetCount;
  for (let i = 0; i < remaining; i++) {
    const other = otherShapes[randomInRange(0, otherShapes.length - 1)];
    items.push({
      uid: uid++,
      shape: other,
      color: SHAPE_COLORS[randomInRange(0, SHAPE_COLORS.length - 1)],
      rotation: randomInRange(0, 3) * 45,
    });
  }

  return { targetShape, grid: shuffleArray(items) };
}

/**
 * Hook pour l'exercice "Trouve les formes".
 * L'enfant doit cliquer sur toutes les formes correspondant au nom demandé.
 */
export function useTrouveFormes(): UseTrouveFormesReturn {
  const { addPoint, removePoint } = useScore();
  const [{ targetShape, grid }, setData] = useState(generateGrid);
  const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set());
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const toggleShape = useCallback(
    (uid: number) => {
      if (isCorrect !== null) return;
      setSelectedIds((prev) => {
        const next = new Set(prev);
        if (next.has(uid)) next.delete(uid);
        else next.add(uid);
        return next;
      });
    },
    [isCorrect]
  );

  const check = useCallback(() => {
    /* Recalcule les IDs cibles à l'intérieur du callback pour éviter des deps instables */
    const correctIdSet = new Set(grid.filter((p) => p.shape.id === targetShape.id).map((p) => p.uid));
    const allCorrectSelected = Array.from(correctIdSet).every((id) => selectedIds.has(id));
    const noWrongSelected = Array.from(selectedIds).every((id) => correctIdSet.has(id));
    const correct = allCorrectSelected && noWrongSelected;

    setIsCorrect(correct);
    if (correct) addPoint();
    else removePoint();
  }, [grid, targetShape.id, selectedIds, addPoint, removePoint]);

  const next = useCallback(() => {
    setData(generateGrid());
    setSelectedIds(new Set());
    setIsCorrect(null);
  }, []);

  return { targetName: targetShape.name, grid, selectedIds, toggleShape, check, isCorrect, next };
}
