import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { shuffleArray } from '../../../utils/shuffleArray';
import { useScore } from '../../../hooks/useScore';

const ALPHABET = 'abcdefghijklmnopqrstuvwxyz'.split('');

interface LetterState {
  /** Lettre affichée (en majuscule ou minuscule) */
  displayed: string;
  /** La bonne réponse (la correspondance dans l'autre casse) */
  answer: string;
  /** 4 propositions mélangées */
  choices: string[];
  /** true si la lettre affichée est en majuscule */
  isUpperCase: boolean;
}

interface UseLettresReturn {
  state: LetterState;
  isCorrect: boolean | null;
  selectChoice: (choice: string) => void;
  next: () => void;
}

/** Génère une question : trouver la correspondance majuscule/minuscule */
function generateLetterQuestion(): LetterState {
  const letter = ALPHABET[randomInRange(0, 25)];
  const isUpperCase = Math.random() > 0.5;

  /* La lettre affichée et la réponse attendue */
  const displayed = isUpperCase ? letter.toUpperCase() : letter;
  const answer = isUpperCase ? letter : letter.toUpperCase();

  /* 3 mauvaises réponses dans la même casse que la réponse */
  const wrongLetters = shuffleArray(ALPHABET.filter((l) => l !== letter)).slice(0, 3);
  const wrongChoices = wrongLetters.map((l) => (isUpperCase ? l : l.toUpperCase()));
  const choices = shuffleArray([answer, ...wrongChoices]);

  return { displayed, answer, choices, isUpperCase };
}

/**
 * Hook pour l'exercice Majuscules/Minuscules.
 * Gère la génération de questions et la validation des réponses.
 */
export function useLettres(): UseLettresReturn {
  const { addPoint, removePoint } = useScore();
  const [state, setState] = useState(generateLetterQuestion);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const selectChoice = useCallback(
    (choice: string) => {
      if (isCorrect !== null) return;
      const correct = choice === state.answer;
      setIsCorrect(correct);
      if (correct) addPoint();
      else removePoint();
    },
    [state.answer, isCorrect, addPoint, removePoint]
  );

  const next = useCallback(() => {
    setState(generateLetterQuestion());
    setIsCorrect(null);
  }, []);

  return { state, isCorrect, selectChoice, next };
}
