function randomInt(min: number, max: number): number {
  if (max < min) return min;
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function resultCapForRange(range: { min: number; max: number }): number {
  return Math.min(99, range.max * 2);
}

function pickStartDelta(
  kind: TransformationKind,
  range: { min: number; max: number }
): { start: number; delta: number; result: number } | null {
  const { min, max } = range;
  const resultMax = resultCapForRange(range);

  for (let attempt = 0; attempt < 120; attempt++) {
    if (kind === 'add') {
      const start = randomInt(min, max);
      const delta = randomInt(min, max);
      const result = start + delta;
      if (result <= resultMax) {
        return { start, delta, result };
      }
    } else {
      const start = randomInt(min, max);
      const dHi = Math.min(max, start);
      if (dHi < min) continue;
      const delta = randomInt(min, dHi);
      const result = start - delta;
      if (result >= 0) {
        return { start, delta, result };
      }
    }
  }
  return null;
}

function pickTemplateFrom(kind: TransformationKind, templates: TransformationTemplate[]): TransformationTemplate {
  const pool = templates.filter((t) => t.kind === kind);
  const fallback = TRANSFORMATION_TEMPLATES.filter((t) => t.kind === kind);
  const usePool = pool.length > 0 ? pool : fallback;
  return usePool[Math.floor(Math.random() * usePool.length)] ?? TRANSFORMATION_TEMPLATES[0];
}

function fallbackTriple(
  kind: TransformationKind,
  range: { min: number; max: number }
): { start: number; delta: number; result: number } {
  const { min, max } = range;
  const cap = resultCapForRange(range);
  if (kind === 'add') {
    let start = min;
    let delta = min;
    let result = start + delta;
    if (result > cap) {
      delta = Math.max(0, cap - start);
      result = start + delta;
    }
    return { start, delta, result };
  }
  const start = max;
  const delta = Math.min(min, start);
  return { start, delta, result: start - delta };
}

export function pickTransformationProblem(
  kind: TransformationKind,
  range: { min: number; max: number },
  templates: TransformationTemplate[] = TRANSFORMATION_TEMPLATES
): TransformationItem {
  const template = pickTemplateFrom(kind, templates);
  const triple = pickStartDelta(kind, range);
  const { start, delta, result } = triple ?? fallbackTriple(kind, range);
  const { story, question } = template.build({ start, delta, result });

  return {
    kind,
    unit: template.unit,
    start,
    delta,
    story,
    question,
  };
}

export function pickTransformationRound(
  range: { min: number; max: number },
  templates: TransformationTemplate[] = TRANSFORMATION_TEMPLATES
): TransformationRound {
  return {
    addition: pickTransformationProblem('add', range, templates),
    subtraction: pickTransformationProblem('sub', range, templates),
  };
}

export function transformationExpected(item: TransformationItem): number {
  return item.kind === 'add' ? item.start + item.delta : item.start - item.delta;
}
