import React from 'react';
import { ExerciseWrapper } from '../../../../components/ExerciseWrapper';
import { RangeSelector } from '../../../../components/RangeSelector';
import { NumPad } from '../../../../components/exercises/NumPad';
import { Feedback } from '../../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../../hooks/useExerciseAnswerLimit';
import { useProbleme, EquationField } from './useProbleme';

/**
 * Exercice de problèmes : l'enfant lit un énoncé et doit le traduire
 * en équation en choisissant l'opération (+/-) et en remplissant les nombres.
 */
export function Probleme(): React.ReactElement {
  const {
    problem, selectedField, setSelectedField, values,
    selectedOperator, toggleOperator, currentValue, setCurrentValue,
    advanceOrCheck, isCorrect, next, range, updateRange,
  } = useProbleme();
  const { wrapNext } = useExerciseAnswerLimit('/maths/calculs');

  /** Style d'une case de l'équation (surlignée si sélectionnée) */
  const boxStyle = (field: EquationField): string =>
    `equation-box ${selectedField === field ? 'equation-box-selected' : ''} ${values[field] ? 'equation-box-filled' : ''}`;

  return (
    <ExerciseWrapper title="Problèmes" backPath="/maths/calculs">
      <RangeSelector range={range} onChange={updateRange} />

      {/* Énoncé du problème */}
      <div className="problem-text">{problem.text}</div>

      {/* Équation à construire : [a] [+/-] [b] = [résultat] */}
      {isCorrect === null && (
        <div className="equation-builder">
          <div className={boxStyle('a')} onClick={() => setSelectedField('a')}>
            {values.a || '_'}
          </div>

          <button
            className={`operator-toggle ${selectedOperator ? 'operator-toggle-selected' : ''}`}
            onClick={toggleOperator}
          >
            {selectedOperator || '?'}
          </button>

          <div className={boxStyle('b')} onClick={() => setSelectedField('b')}>
            {values.b || '_'}
          </div>

          <span className="equation-builder-equal">=</span>

          <div className={boxStyle('result')} onClick={() => setSelectedField('result')}>
            {values.result || '_'}
          </div>
        </div>
      )}

      {/* Pavé numérique ou feedback */}
      {isCorrect === null ? (
        <NumPad value={currentValue} onChange={setCurrentValue} onValidate={advanceOrCheck} />
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={`${problem.a} ${problem.operation} ${problem.b} = ${problem.answer}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
