import React from 'react';
import { SubjectList } from '../../components/SubjectList';
import { filterMathsThemesForGrade } from '../../data/navFilter';
import { useSchoolYear } from '../../hooks/useSchoolYear';

/** Page Mathématiques : choix entre Réglette, Calculs, Comparaison, Géométrie */
export function MathsHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterMathsThemesForGrade(grade);
  return <SubjectList title="Mathématiques" items={items} backPath="/" />;
}
