import React from 'react';

export interface AnalogClockProps {
  hour12: number;
  minute: number;
  hideMinuteHand?: boolean;
}

function polar(cx: number, cy: number, length: number, degrees: number): { x: number; y: number } {
  const rad = ((degrees - 90) * Math.PI) / 180;
  return {
    x: cx + length * Math.cos(rad),
    y: cy + length * Math.sin(rad),
  };
}

/** Palette de couleurs : un nombre = une couleur */
const CLOCK_NUMBER_COLORS: Record<number, string> = {
  12: '#C0392B', 1: '#3498DB', 2: '#27AE60', 3: '#9B59B6', 4: '#E67E22', 5: '#1ABC9C',
  6: '#E91E63', 7: '#2980B9', 8: '#8E44AD', 9: '#D35400', 10: '#16A085', 11: '#F39C12',
};

/** Cadran analogique SVG (graduations 12, aiguilles heures / minutes). */
export function AnalogClock({
  hour12,
  minute,
  hideMinuteHand = false,
}: AnalogClockProps): React.ReactElement {
  const cx = 100;
  const cy = 100;
  const h = ((hour12 % 12) + minute / 60) * 30;
  const m = minute * 6;
  const tipH = polar(cx, cy, 48, h);
  const tipM = polar(cx, cy, 72, m);

  /* Graduations des heures (12 marques principales) - plus courtes pour laisser place aux nombres */
  const hourTicks = Array.from({ length: 12 }, (_, i) => {
    const outer = polar(cx, cy, 82, i * 30);
    const inner = polar(cx, cy, i % 3 === 0 ? 66 : 72, i * 30);
    return (
      <line
        key={`h-${i}`}
        x1={inner.x}
        y1={inner.y}
        x2={outer.x}
        y2={outer.y}
        stroke="currentColor"
        strokeWidth={i % 3 === 0 ? 3 : 1.5}
        strokeLinecap="round"
      />
    );
  });

  /* Graduations des minutes (60 petites marques entre les heures) */
  const minuteTicks = Array.from({ length: 60 }, (_, i) => {
    const deg = i * 6;
    const outer = polar(cx, cy, 82, deg);
    const inner = polar(cx, cy, 78, deg);
    const isHourPos = i % 5 === 0; // 12, 3, 6, 9 = marques des heures déjà dessinées
    if (isHourPos) return null; // pas de double trait sur les heures
    return (
      <line
        key={`m-${i}`}
        x1={inner.x}
        y1={inner.y}
        x2={outer.x}
        y2={outer.y}
        stroke="currentColor"
        strokeWidth={0.8}
        strokeOpacity={0.6}
        strokeLinecap="round"
      />
    );
  });

  const minuteTicksFiltered = minuteTicks.filter(Boolean);

  /* Numéros 1 à 12 - décalés vers le centre pour bien se détacher des graduations */
  const numbers = Array.from({ length: 12 }, (_, i) => {
    const n = i === 0 ? 12 : i;
    const pos = polar(cx, cy, 54, i * 30);
    return (
      <text
        key={`n-${i}`}
        x={pos.x}
        y={pos.y}
        textAnchor="middle"
        dominantBaseline="central"
        className="analog-clock-number"
        fill={CLOCK_NUMBER_COLORS[n]}
      >
        {n}
      </text>
    );
  });

  return (
    <svg
      className="sciences-analog-clock"
      viewBox="0 0 200 200"
      width={260}
      height={260}
      aria-hidden
    >
      <circle cx={cx} cy={cy} r={92} fill="#fff" stroke="currentColor" strokeWidth={3} />
      {minuteTicksFiltered}
      {hourTicks}
      {numbers}
      {!hideMinuteHand && (
        <line
          x1={cx}
          y1={cy}
          x2={tipM.x}
          y2={tipM.y}
          stroke="#2c3e50"
          strokeWidth={4}
          strokeLinecap="round"
        />
      )}
      <line
        x1={cx}
        y1={cy}
        x2={tipH.x}
        y2={tipH.y}
        stroke="#4a90d9"
        strokeWidth={5}
        strokeLinecap="round"
      />
      <circle cx={cx} cy={cy} r={6} fill="#2c3e50" />
    </svg>
  );
}
