import React from 'react';

interface NumPadProps {
  /** Valeur actuellement saisie (sous forme de string) */
  value: string;
  /** Appelé à chaque modification de la valeur */
  onChange: (value: string) => void;
  /** Appelé quand l'utilisateur valide sa réponse */
  onValidate: () => void;
  /** Désactive le pavé (ex: après validation) */
  disabled?: boolean;
}

/**
 * Pavé numérique tactile optimisé pour mobile.
 * Affiche la valeur saisie et des boutons 0-9 + supprimer + valider.
 */
export function NumPad({ value, onChange, onValidate, disabled }: NumPadProps): React.ReactElement {
  /** Ajoute un chiffre à la saisie */
  const handleDigit = (digit: number): void => {
    if (disabled) return;
    onChange(value + String(digit));
  };

  /** Supprime le dernier chiffre */
  const handleDelete = (): void => {
    if (disabled) return;
    onChange(value.slice(0, -1));
  };

  return (
    <div className="numpad">
      {/* Affichage de la valeur saisie */}
      <div className="numpad-display">{value || '?'}</div>

      {/* Chiffres 1 à 9 */}
      {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((digit) => (
        <button
          key={digit}
          className="numpad-btn"
          onClick={() => handleDigit(digit)}
          disabled={disabled}
        >
          {digit}
        </button>
      ))}

      {/* Ligne du bas : supprimer, 0, valider */}
      <button className="numpad-btn numpad-btn-delete" onClick={handleDelete} disabled={disabled}>
        ⌫
      </button>
      <button className="numpad-btn" onClick={() => handleDigit(0)} disabled={disabled}>
        0
      </button>
      <button className="numpad-btn numpad-btn-validate" onClick={onValidate} disabled={disabled || !value}>
        ✓
      </button>
    </div>
  );
}
