import React from 'react';
import { Operator } from '../../utils/generateOperation';
import { useOperation } from '../../hooks/useOperation';
import { useExerciseAnswerLimit } from '../../hooks/useExerciseAnswerLimit';
import { RangeSelector } from '../RangeSelector';
import { Feedback } from '../Feedback';
import { NumPad } from './NumPad';

interface OperationExerciseProps {
  /** Opérateur mathématique (+, -, ×, ÷) */
  operator: Operator;
  /** Plage de nombres par défaut */
  defaultMin: number;
  defaultMax: number;
  /** Retour après 10 questions (menu parent) */
  backPath: string;
}

/**
 * Composant générique pour les exercices de calcul.
 * Affiche une équation avec un nombre manquant, un pavé numérique et un feedback.
 * Partagé par Addition, Soustraction, Multiplication et Division.
 */
export function OperationExercise({
  operator,
  defaultMin,
  defaultMax,
  backPath,
}: OperationExerciseProps): React.ReactElement {
  const { wrapNext } = useExerciseAnswerLimit(backPath);
  const { operation, answer, setAnswer, isCorrect, check, next, range, updateRange } =
    useOperation(operator, defaultMin, defaultMax);

  /** Construit l'affichage de l'équation avec le "?" au bon endroit */
  const displayValue = (index: 0 | 1 | 2, value: number): string | React.ReactNode => {
    if (operation.missingIndex === index) {
      return answer || '?';
    }
    return String(value);
  };

  return (
    <>
      <RangeSelector range={range} onChange={updateRange} />

      {/* Équation : A op B = C */}
      <div className="equation">
        <span className={operation.missingIndex === 0 ? 'equation-missing' : ''}>
          {displayValue(0, operation.a)}
        </span>
        <span>{operation.operator}</span>
        <span className={operation.missingIndex === 1 ? 'equation-missing' : ''}>
          {displayValue(1, operation.b)}
        </span>
        <span>=</span>
        <span className={operation.missingIndex === 2 ? 'equation-missing' : ''}>
          {displayValue(2, operation.result)}
        </span>
      </div>

      {/* Pavé numérique ou feedback */}
      {isCorrect === null ? (
        <NumPad value={answer} onChange={setAnswer} onValidate={check} />
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={isCorrect ? undefined : `La réponse était ${operation.answer}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </>
  );
}
