import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { useScore } from '../../../hooks/useScore';

/** Génère un entier entre 1 et 99 qui n'est pas un multiple de 10 */
function generateNumber(): number {
  let n: number;
  do {
    n = randomInRange(1, 99);
  } while (n % 10 === 0);
  return n;
}

export interface UseDizainesReturn {
  n: number;
  lowerInput: string;
  upperInput: string;
  setLowerInput: (v: string) => void;
  setUpperInput: (v: string) => void;
  isCorrect: boolean | null;
  check: () => void;
  next: () => void;
  lowerExpected: number;
  upperExpected: number;
}

/**
 * Dizaine inférieure / supérieure : ex. 65 → 60 et 70
 */
export function useDizaines(): UseDizainesReturn {
  const { addPoint, removePoint } = useScore();
  const [n, setN] = useState(() => generateNumber());
  const [lowerInput, setLowerInput] = useState('');
  const [upperInput, setUpperInput] = useState('');
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const lowerExpected = Math.floor(n / 10) * 10;
  const upperExpected = lowerExpected + 10;

  const check = useCallback(() => {
    if (isCorrect !== null) return;
    const l = parseInt(lowerInput, 10);
    const u = parseInt(upperInput, 10);
    if (Number.isNaN(l) || Number.isNaN(u)) return;
    const ok = l === lowerExpected && u === upperExpected;
    setIsCorrect(ok);
    if (ok) addPoint();
    else removePoint();
  }, [lowerInput, upperInput, lowerExpected, upperExpected, isCorrect, addPoint, removePoint]);

  const next = useCallback(() => {
    setN(generateNumber());
    setLowerInput('');
    setUpperInput('');
    setIsCorrect(null);
  }, []);

  return {
    n,
    lowerInput,
    upperInput,
    setLowerInput,
    setUpperInput,
    isCorrect,
    check,
    next,
    lowerExpected,
    upperExpected,
  };
}
