import { useState, useCallback, useMemo, useEffect } from 'react';
import { useScore } from '../../../../hooks/useScore';
import {
  pickTransformationRound,
  transformationExpected,
  type TransformationItem,
  type TransformationRound,
} from '../../../../data/transformation-problems';

export type TransformationPhase = 'add' | 'sub';

/** Cases du diagramme puis équation (ordre identique aux données du problème). */
export type TransformationField =
  | 'diag_a'
  | 'diag_b'
  | 'diag_c'
  | 'eq_a'
  | 'eq_b'
  | 'eq_result';

const EMPTY_FIELDS: Record<TransformationField, string> = {
  diag_a: '',
  diag_b: '',
  diag_c: '',
  eq_a: '',
  eq_b: '',
  eq_result: '',
};

function digitsOnly(value: string, maxLen: number): string {
  return value.replace(/\D/g, '').slice(0, maxLen);
}

export interface UseTransformationReturn {
  phase: TransformationPhase;
  current: TransformationItem;
  fields: Record<TransformationField, string>;
  setField: (f: TransformationField, v: string) => void;
  activeField: TransformationField;
  setActiveField: (f: TransformationField) => void;
  padValue: string;
  setPadValue: (v: string) => void;
  feedback: boolean | null;
  validate: () => 'incomplete' | 'done';
  applyFeedbackNext: () => void;
  expected: number;
  equationOp: '+' | '−';
}

/**
 * @param numberRange plage pour tirer **start** et **delta**.
 */
export function useTransformation(numberRange: { min: number; max: number }): UseTransformationReturn {
  const { addPoint, removePoint } = useScore();
  const [phase, setPhase] = useState<TransformationPhase>('add');
  const [roundPack, setRoundPack] = useState<TransformationRound>(() =>
    pickTransformationRound(numberRange)
  );
  const [fields, setFields] = useState<Record<TransformationField, string>>(() => ({
    ...EMPTY_FIELDS,
  }));
  const [activeField, setActiveFieldState] = useState<TransformationField>('diag_a');
  const [feedback, setFeedback] = useState<boolean | null>(null);

  useEffect(() => {
    setPhase('add');
    setRoundPack(pickTransformationRound(numberRange));
    setFields({ ...EMPTY_FIELDS });
    setActiveFieldState('diag_a');
    setFeedback(null);
  }, [numberRange.min, numberRange.max]);

  const current = phase === 'add' ? roundPack.addition : roundPack.subtraction;

  const expected = useMemo(() => transformationExpected(current), [current]);

  const equationOp = current.kind === 'add' ? '+' : '−';

  const setField = useCallback((f: TransformationField, v: string) => {
    setFields((prev) => ({ ...prev, [f]: digitsOnly(v, 3) }));
  }, []);

  const setActiveField = useCallback((f: TransformationField) => {
    setActiveFieldState(f);
  }, []);

  const padValue = fields[activeField];
  const setPadValue = useCallback(
    (v: string) => {
      setField(activeField, digitsOnly(v, 3));
    },
    [activeField, setField]
  );

  const validate = useCallback(() => {
    if (feedback !== null) return 'done';
    const parse = (s: string): number | null => {
      if (!s.trim()) return null;
      const n = parseInt(s, 10);
      return Number.isNaN(n) ? null : n;
    };

    const da = parse(fields.diag_a);
    const db = parse(fields.diag_b);
    const dc = parse(fields.diag_c);
    const ea = parse(fields.eq_a);
    const eb = parse(fields.eq_b);
    const er = parse(fields.eq_result);

    if (
      da === null ||
      db === null ||
      dc === null ||
      ea === null ||
      eb === null ||
      er === null
    ) {
      return 'incomplete';
    }

    const { start, delta, kind } = current;
    const okDiag = da === start && db === delta && dc === expected;
    const okEq = ea === start && eb === delta && er === expected;
    const okMatch = da === ea && db === eb && dc === er;
    let okMath = false;
    if (kind === 'add') {
      okMath = ea + eb === er;
    } else {
      okMath = ea - eb === er;
    }

    const ok = okDiag && okEq && okMatch && okMath;
    setFeedback(ok);
    if (ok) addPoint();
    else removePoint();
    return 'done';
  }, [fields, current, expected, feedback, addPoint, removePoint]);

  const applyFeedbackNext = useCallback(() => {
    if (feedback === false) {
      setFeedback(null);
      return;
    }
    if (phase === 'add') {
      setPhase('sub');
      setFeedback(null);
      setFields({ ...EMPTY_FIELDS });
      setActiveFieldState('diag_a');
      return;
    }
    setRoundPack(pickTransformationRound(numberRange));
    setPhase('add');
    setFeedback(null);
    setFields({ ...EMPTY_FIELDS });
    setActiveFieldState('diag_a');
  }, [feedback, phase, numberRange.min, numberRange.max]);

  return {
    phase,
    current,
    fields,
    setField,
    activeField,
    setActiveField,
    padValue,
    setPadValue,
    feedback,
    validate,
    applyFeedbackNext,
    expected,
    equationOp,
  };
}
