import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { SoundBoxes } from './SoundBoxes';
import { useSons } from './useSons';
import { SOUND_THEMES } from '../../../data/mots-sons';

/**
 * Exercice de découpe en sons : un mot affiché, l'enfant place les sons
 * dans les cases en cliquant sur les chips disponibles.
 * Filtrage par thème de son possible.
 */
export function DecoupeEnSons(): React.ReactElement {
  const {
    state, placedSounds, isCorrect, placeSound, removeLast,
    next, themeFilter, setThemeFilter,
  } = useSons();
  const { wrapNext } = useExerciseAnswerLimit('/francais/sons');

  /** Détermine si un son a déjà été utilisé (pour griser le chip) */
  const isUsed = (sound: string, index: number): boolean => {
    /* Compte combien de fois ce son apparaît dans les chips disponibles jusqu'à cet index */
    const availableUpToIndex = state.availableSounds.slice(0, index + 1).filter((s) => s === sound).length;
    const usedCount = placedSounds.filter((s) => s === sound).length;
    const totalAvailable = state.availableSounds.filter((s) => s === sound).length;
    return usedCount >= totalAvailable || (availableUpToIndex <= usedCount);
  };

  return (
    <ExerciseWrapper title="Découpe en sons" backPath="/francais/sons">
      {/* Filtre par thème de son */}
      <div className="theme-filter">
        <button
          className={`theme-filter-btn ${themeFilter === null ? 'theme-filter-btn-active' : ''}`}
          onClick={() => setThemeFilter(null)}
        >
          Tous
        </button>
        {SOUND_THEMES.map((theme) => (
          <button
            key={theme}
            className={`theme-filter-btn ${themeFilter === theme ? 'theme-filter-btn-active' : ''}`}
            onClick={() => setThemeFilter(theme)}
          >
            {theme}
          </button>
        ))}
      </div>

      {/* Mot à découper */}
      <div className="sound-boxes-word">{state.wordData.word}</div>

      {/* Cases de sons */}
      <SoundBoxes
        totalBoxes={state.wordData.sounds.length}
        placedSounds={placedSounds}
        correctSounds={state.wordData.sounds}
        isCorrect={isCorrect}
      />

      {/* Chips de sons disponibles ou feedback */}
      {isCorrect === null ? (
        <>
          <div className="sound-boxes-row" style={{ marginTop: 8 }}>
            {state.availableSounds.map((sound, i) => (
              <button
                key={`${sound}-${i}`}
                className={`sound-chip ${isUsed(sound, i) ? 'sound-chip-used' : ''}`}
                onClick={() => placeSound(sound)}
                disabled={isUsed(sound, i)}
              >
                {sound}
              </button>
            ))}
          </div>
          {/* Bouton pour retirer le dernier son */}
          {placedSounds.length > 0 && (
            <button
              onClick={removeLast}
              style={{ color: '#E74C3C', background: 'none', fontSize: 16 }}
            >
              ← Retirer le dernier
            </button>
          )}
        </>
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={`${state.wordData.word} → ${state.wordData.sounds.join(' · ')}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
