import React from 'react';
import type { TransformationItem } from '../../../../data/transformation-problems';
import type { TransformationField } from './useTransformation';

interface TransformationBarInteractiveProps {
  item: TransformationItem;
  fields: Record<TransformationField, string>;
  activeField: TransformationField;
  onFieldChange: (f: TransformationField, v: string) => void;
  onFieldFocus: (f: TransformationField) => void;
  disabled: boolean;
}

function BarInput(props: {
  id: string;
  field: TransformationField;
  value: string;
  active: boolean;
  disabled: boolean;
  onFieldChange: (f: TransformationField, v: string) => void;
  onFieldFocus: (f: TransformationField) => void;
  ariaLabel: string;
}): React.ReactElement {
  const { id, field, value, active, disabled, onFieldChange, onFieldFocus, ariaLabel } = props;
  return (
    <input
      id={id}
      type="text"
      inputMode="numeric"
      autoComplete="off"
      className={`trans-bar-input ${active ? 'trans-bar-input-active' : ''}`}
      value={value}
      disabled={disabled}
      onChange={(e) => onFieldChange(field, e.target.value)}
      onFocus={() => onFieldFocus(field)}
      placeholder="?"
      aria-label={ariaLabel}
    />
  );
}

/**
 * Diagramme en barres : l’enfant remplit les nombres (2 lignes).
 */
export function TransformationBarInteractive({
  item,
  fields,
  activeField,
  onFieldChange,
  onFieldFocus,
  disabled,
}: TransformationBarInteractiveProps): React.ReactElement {
  const flexSubLeft = item.delta;
  const flexSubRight = Math.max(1, item.start - item.delta);

  if (item.kind === 'add') {
    const flexTopLeft = item.start;
    const flexTopRight = item.delta;
    return (
      <div className="trans-bar-wrap">
        <p className="trans-bar-heading">Diagramme en barres</p>
        <div className="trans-bar trans-bar-add">
          <div className="trans-bar-row trans-bar-row-split">
            <div
              className="trans-bar-cell trans-bar-cell-blue"
              style={{ flex: flexTopLeft }}
            >
              <BarInput
                id="trans-diag-a"
                field="diag_a"
                value={fields.diag_a}
                active={activeField === 'diag_a'}
                disabled={disabled}
                onFieldChange={onFieldChange}
                onFieldFocus={onFieldFocus}
                ariaLabel="Première partie (dizaines ou total de départ)"
              />
            </div>
            <div
              className="trans-bar-cell trans-bar-cell-yellow"
              style={{ flex: flexTopRight }}
            >
              <span className="trans-bar-plus" aria-hidden>
                +
              </span>
              <BarInput
                id="trans-diag-b"
                field="diag_b"
                value={fields.diag_b}
                active={activeField === 'diag_b'}
                disabled={disabled}
                onFieldChange={onFieldChange}
                onFieldFocus={onFieldFocus}
                ariaLabel="Ce qui s’ajoute"
              />
            </div>
          </div>
          <div className="trans-bar-row trans-bar-row-full">
            <div className="trans-bar-cell trans-bar-cell-green trans-bar-cell-dashed trans-bar-cell-grow">
              <BarInput
                id="trans-diag-c"
                field="diag_c"
                value={fields.diag_c}
                active={activeField === 'diag_c'}
                disabled={disabled}
                onFieldChange={onFieldChange}
                onFieldFocus={onFieldFocus}
                ariaLabel="Total (résultat)"
              />
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="trans-bar-wrap">
      <p className="trans-bar-heading">Diagramme en barres</p>
      <div className="trans-bar trans-bar-sub">
        <div className="trans-bar-row trans-bar-row-full">
          <div className="trans-bar-cell trans-bar-cell-blue trans-bar-cell-grow">
            <BarInput
              id="trans-diag-a"
              field="diag_a"
              value={fields.diag_a}
              active={activeField === 'diag_a'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Nombre au départ (total)"
            />
          </div>
        </div>
        <div className="trans-bar-row trans-bar-row-split">
          <div
            className="trans-bar-cell trans-bar-cell-red"
            style={{ flex: flexSubLeft }}
          >
            <span className="trans-bar-minus" aria-hidden>
              −
            </span>
            <BarInput
              id="trans-diag-b"
              field="diag_b"
              value={fields.diag_b}
              active={activeField === 'diag_b'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Ce qu’on enlève"
            />
          </div>
          <div
            className="trans-bar-cell trans-bar-cell-green trans-bar-cell-dashed"
            style={{ flex: flexSubRight }}
          >
            <BarInput
              id="trans-diag-c"
              field="diag_c"
              value={fields.diag_c}
              active={activeField === 'diag_c'}
              disabled={disabled}
              onFieldChange={onFieldChange}
              onFieldFocus={onFieldFocus}
              ariaLabel="Ce qui reste"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
