import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { useScore } from '../../../hooks/useScore';
import { WORDS, SOUND_THEMES, SoundTheme, WordData } from '../../../data/mots-sons';

/**
 * Correspondances entre un thème de son et ses variantes graphiques.
 * Par exemple, le son "an" s'écrit aussi "en" dans certains mots.
 */
const SOUND_VARIANTS: Record<string, string[]> = {
  oi: ['oi'],
  ou: ['ou'],
  an: ['an', 'en'],
  on: ['on'],
  in: ['in', 'ain'],
  ch: ['ch'],
  ai: ['ai', 'è', 'ê'],
  eau: ['eau', 'au'],
};

interface TrouveSonState {
  word: WordData;
  targetSound: SoundTheme;
  /** Indices des cases où se trouve le son cible */
  correctIndices: number[];
}

interface UseTrouveSonReturn {
  state: TrouveSonState;
  /** Indices sélectionnés par l'enfant */
  selectedIndices: Set<number>;
  toggleIndex: (index: number) => void;
  check: () => void;
  isCorrect: boolean | null;
  next: () => void;
  themeFilter: SoundTheme | null;
  setThemeFilter: (theme: SoundTheme | null) => void;
}

/** Génère une question : trouver où se situe un son dans un mot */
function generateQuestion(themeFilter: SoundTheme | null): TrouveSonState {
  /* Choisit un son cible */
  const targetSound: SoundTheme = themeFilter
    || SOUND_THEMES[randomInRange(0, SOUND_THEMES.length - 1)];

  /* Filtre les mots qui contiennent ce son */
  const pool = WORDS.filter((w) => w.themes.includes(targetSound));
  if (pool.length === 0) return generateQuestion(null); /* fallback */

  const word = pool[randomInRange(0, pool.length - 1)];
  const variants = SOUND_VARIANTS[targetSound] || [targetSound];

  /* Trouve tous les indices où le son apparaît */
  const correctIndices = word.sounds
    .map((s, i) => (variants.includes(s) ? i : -1))
    .filter((i) => i >= 0);

  return { word, targetSound, correctIndices };
}

/**
 * Hook pour l'exercice "Trouve le son".
 * L'enfant doit cliquer sur la/les case(s) où se situe le son demandé.
 */
export function useTrouveSon(): UseTrouveSonReturn {
  const { addPoint, removePoint } = useScore();
  const [themeFilter, setThemeFilter] = useState<SoundTheme | null>(null);
  const [state, setState] = useState(() => generateQuestion(null));
  const [selectedIndices, setSelectedIndices] = useState<Set<number>>(new Set());
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const toggleIndex = useCallback(
    (index: number) => {
      if (isCorrect !== null) return;
      setSelectedIndices((prev) => {
        const next = new Set(prev);
        if (next.has(index)) next.delete(index);
        else next.add(index);
        return next;
      });
    },
    [isCorrect]
  );

  const check = useCallback(() => {
    const allCorrect = state.correctIndices.every((i) => selectedIndices.has(i));
    const noWrong = Array.from(selectedIndices).every((i) => state.correctIndices.includes(i));
    const correct = allCorrect && noWrong;

    setIsCorrect(correct);
    if (correct) addPoint();
    else removePoint();
  }, [state.correctIndices, selectedIndices, addPoint, removePoint]);

  const next = useCallback(() => {
    setState(generateQuestion(themeFilter));
    setSelectedIndices(new Set());
    setIsCorrect(null);
  }, [themeFilter]);

  const handleSetThemeFilter = useCallback((theme: SoundTheme | null) => {
    setThemeFilter(theme);
    setState(generateQuestion(theme));
    setSelectedIndices(new Set());
    setIsCorrect(null);
  }, []);

  return {
    state, selectedIndices, toggleIndex, check, isCorrect,
    next, themeFilter, setThemeFilter: handleSetThemeFilter,
  };
}
