import React from 'react';
import { SubjectList } from '../components/SubjectList';
import { filterSubjectsForGrade } from '../data/navFilter';
import { useSchoolYear } from '../hooks/useSchoolYear';

/** Page d'accueil : choix de matière (Maths, Français, Sciences…) */
export function Home(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterSubjectsForGrade(grade);
  return <SubjectList title="Que veux-tu apprendre ?" items={items} />;
}
