import { useState, useCallback, useMemo } from 'react';
import { useScore } from '../../../hooks/useScore';

export type LireHeureMode = 'hour' | 'minutes' | 'full';

export type ClockField = 'hour' | 'minute';

export interface LireHeureQuestion {
  mode: LireHeureMode;
  hour12: number;
  minute: number;
}

function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function digitsOnly(value: string, maxLen: number): string {
  return value.replace(/\D/g, '').slice(0, maxLen);
}

function newQuestion(mode: LireHeureMode): LireHeureQuestion {
  if (mode === 'hour') {
    return { mode, hour12: randomInt(1, 12), minute: 0 };
  }
  if (mode === 'minutes') {
    return { mode, hour12: 3, minute: randomInt(1, 59) };
  }
  return { mode, hour12: randomInt(1, 12), minute: randomInt(0, 59) };
}

export function useLireHeure(): {
  mode: LireHeureMode;
  setMode: (m: LireHeureMode) => void;
  question: LireHeureQuestion;
  hourInput: string;
  minuteInput: string;
  setHourInput: (v: string) => void;
  setMinuteInput: (v: string) => void;
  activeField: ClockField;
  setActiveField: (f: ClockField) => void;
  padValue: string;
  setPadValue: (v: string) => void;
  feedback: boolean | null;
  check: () => 'incomplete' | 'done';
  next: () => void;
  hideMinuteHand: boolean;
} {
  const { addPoint, removePoint } = useScore();
  const [mode, setModeState] = useState<LireHeureMode>('hour');
  const [question, setQuestion] = useState<LireHeureQuestion>(() => newQuestion('hour'));
  const [hourInput, setHourInputRaw] = useState('');
  const [minuteInput, setMinuteInputRaw] = useState('');
  const [activeField, setActiveField] = useState<ClockField>('hour');
  const [feedback, setFeedback] = useState<boolean | null>(null);

  const setMode = useCallback((m: LireHeureMode) => {
    setModeState(m);
    setQuestion(newQuestion(m));
    setHourInputRaw('');
    setMinuteInputRaw('');
    setFeedback(null);
    setActiveField(m === 'minutes' ? 'minute' : 'hour');
  }, []);

  const setHourInput = useCallback((v: string) => {
    setHourInputRaw(digitsOnly(v, 2));
  }, []);

  const setMinuteInput = useCallback((v: string) => {
    setMinuteInputRaw(digitsOnly(v, 2));
  }, []);

  const padValue = useMemo(
    () => (activeField === 'hour' ? hourInput : minuteInput),
    [activeField, hourInput, minuteInput]
  );

  const setPadValue = useCallback(
    (v: string) => {
      const cleaned = digitsOnly(v, 2);
      if (activeField === 'hour') setHourInputRaw(cleaned);
      else setMinuteInputRaw(cleaned);
    },
    [activeField]
  );

  const hideMinuteHand = mode === 'hour';

  const check = useCallback((): 'incomplete' | 'done' => {
    if (feedback !== null) return 'done';

    const qh = question.hour12;
    const qm = question.minute;

    if (mode === 'hour') {
      if (!hourInput.trim()) return 'incomplete';
      const h = parseInt(hourInput, 10);
      if (Number.isNaN(h) || h < 1 || h > 12) return 'incomplete';
      const ok = h === qh;
      setFeedback(ok);
      if (ok) addPoint();
      else removePoint();
      return 'done';
    }

    if (mode === 'minutes') {
      if (!minuteInput.trim()) return 'incomplete';
      const m = parseInt(minuteInput, 10);
      if (Number.isNaN(m) || m < 0 || m > 59) return 'incomplete';
      const ok = m === qm;
      setFeedback(ok);
      if (ok) addPoint();
      else removePoint();
      return 'done';
    }

    if (!hourInput.trim() || !minuteInput.trim()) return 'incomplete';
    const h = parseInt(hourInput, 10);
    const m = parseInt(minuteInput, 10);
    if (Number.isNaN(h) || h < 1 || h > 12 || Number.isNaN(m) || m < 0 || m > 59) {
      return 'incomplete';
    }
    const ok = h === qh && m === qm;
    setFeedback(ok);
    if (ok) addPoint();
    else removePoint();
    return 'done';
  }, [feedback, mode, question, hourInput, minuteInput, addPoint, removePoint]);

  const next = useCallback(() => {
    setQuestion(newQuestion(mode));
    setHourInputRaw('');
    setMinuteInputRaw('');
    setFeedback(null);
    setActiveField(mode === 'minutes' ? 'minute' : 'hour');
  }, [mode]);

  return {
    mode,
    setMode,
    question,
    hourInput,
    minuteInput,
    setHourInput,
    setMinuteInput,
    activeField,
    setActiveField,
    padValue,
    setPadValue,
    feedback,
    check,
    next,
    hideMinuteHand,
  };
}
