/**
 * Arbre de navigation déclaratif.
 * Chaque page de listing (Home, MathsHome, etc.) importe la section pertinente.
 * Pour ajouter un exercice : créer le dossier + ajouter une entrée ici.
 *
 * Option `grades` : années pour lesquelles l'exercice est proposé.
 * Si absent, toutes les années listées dans getAvailableSchoolYears() (via DEFAULT) s'appliquent.
 * Une année n'apparaît dans le sélecteur que si au moins un exercice la cible.
 */

import type { SchoolYear } from './schoolYear';

/** Représente un élément de navigation (matière, thème, sous-thème ou exercice) */
export interface NavigationItem {
  id: string;
  label: string;
  path: string;
  icon?: string;
  description?: string;
  /** Années scolaires ciblées (sinon : tout le primaire configuré dans schoolYear.ts) */
  grades?: SchoolYear[];
}

