export function pickElectriciteQuestion(excludeId?: string): ElectriciteQuestion {
  const pool = excludeId ? ELECTRICITE_QUESTIONS.filter((q) => q.id !== excludeId) : [...ELECTRICITE_QUESTIONS];
  return pool[Math.floor(Math.random() * pool.length)] ?? ELECTRICITE_QUESTIONS[0];
}
