import React from 'react';
import { SubjectList } from '../../../components/SubjectList';
import { filterCalculosSubthemesForGrade } from '../../../data/navFilter';
import { useSchoolYear } from '../../../hooks/useSchoolYear';

/** Page de listing des sous-thèmes de Calculs (addition, soustraction, etc.) */
export function CalculsHome(): React.ReactElement {
  const { grade } = useSchoolYear();
  const items = filterCalculosSubthemesForGrade(grade);
  return <SubjectList title="Calculs" items={items} backPath="/maths" />;
}
