import { useState, useCallback } from 'react';
import { randomInRange } from '../../../utils/randomInRange';
import { shuffleArray } from '../../../utils/shuffleArray';
import { useScore } from '../../../hooks/useScore';
import { SHAPES, SHAPE_COLORS, ShapeDefinition } from '../../../data/formes';

interface FormeState {
  /** Forme correcte à identifier */
  shape: ShapeDefinition;
  /** 4 choix de noms (1 correct + 3 distracteurs) */
  choices: ShapeDefinition[];
  /** Rotation aléatoire en degrés */
  rotation: number;
  /** Couleur de remplissage */
  color: string;
}

interface UseFormesReturn {
  state: FormeState;
  isCorrect: boolean | null;
  selectedId: string | null;
  selectChoice: (id: string) => void;
  next: () => void;
}

/** Génère une question : une forme à identifier parmi 4 propositions */
function generateFormeQuestion(): FormeState {
  const correct = SHAPES[randomInRange(0, SHAPES.length - 1)];
  const others = shuffleArray(SHAPES.filter((s) => s.id !== correct.id)).slice(0, 3);
  const choices = shuffleArray([correct, ...others]);
  const rotation = randomInRange(0, 3) * 45;
  const color = SHAPE_COLORS[randomInRange(0, SHAPE_COLORS.length - 1)];
  return { shape: correct, choices, rotation, color };
}

/**
 * Hook pour l'exercice de reconnaissance de formes géométriques.
 * Gère la sélection de la forme, les choix et le score.
 */
export function useFormes(): UseFormesReturn {
  const { addPoint, removePoint } = useScore();
  const [state, setState] = useState(generateFormeQuestion);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const selectChoice = useCallback(
    (id: string) => {
      if (isCorrect !== null) return;
      setSelectedId(id);
      const correct = id === state.shape.id;
      setIsCorrect(correct);
      if (correct) addPoint();
      else removePoint();
    },
    [state.shape.id, isCorrect, addPoint, removePoint]
  );

  const next = useCallback(() => {
    setState(generateFormeQuestion());
    setSelectedId(null);
    setIsCorrect(null);
  }, []);

  return { state, isCorrect, selectedId, selectChoice, next };
}
