import React from 'react';
import { Button } from '@codegouvfr/react-dsfr/Button';
import { ScoreDisplay } from './ScoreDisplay';
import { OptionsMenu } from './OptionsMenu';

interface ExerciseWrapperProps {
  /** Titre affiché dans l'en-tête */
  title: string;
  /** Chemin de retour pour le bouton flèche */
  backPath: string;
  children: React.ReactNode;
}

/**
 * Wrapper plein écran pour les exercices.
 * Affiche un bouton retour en haut à gauche et le score en haut à droite.
 * Remplace le Layout classique quand un exercice est actif.
 */
export function ExerciseWrapper({ title, backPath, children }: ExerciseWrapperProps): React.ReactElement {
  return (
    <div className="exercise-wrapper">
      <header className="exercise-header" style={{ position: 'relative' }}>
        <Button
          priority="tertiary"
          iconId="fr-icon-arrow-go-back-line"
          iconPosition="left"
          linkProps={{ to: backPath }}
          className="exercise-back"
        >
          Retour
        </Button>
        <span className="exercise-title">{title}</span>
        <div className="layout-header-actions exercise-header-actions">
          <OptionsMenu variant="exercise" />
          <ScoreDisplay />
        </div>
      </header>
      <div className="exercise-body">
        {children}
      </div>
    </div>
  );
}
