import React from 'react';

interface RangeSelectorProps {
  range: { min: number; max: number };
  onChange: (range: { min: number; max: number }) => void;
}

/**
 * Sélecteur de plage de nombres (min / max).
 * Compact, affiché en haut des exercices de maths pour ajuster la difficulté.
 */
export function RangeSelector({ range, onChange }: RangeSelectorProps): React.ReactElement {
  /** Met à jour min en s'assurant qu'il reste inférieur à max */
  const handleMinChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const value = parseInt(e.target.value, 10);
    if (!isNaN(value) && value < range.max) {
      onChange({ ...range, min: Math.max(0, value) });
    }
  };

  /** Met à jour max en s'assurant qu'il reste supérieur à min */
  const handleMaxChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
    const value = parseInt(e.target.value, 10);
    if (!isNaN(value) && value > range.min) {
      onChange({ ...range, max: value });
    }
  };

  return (
    <div className="range-selector">
      <span>De</span>
      <input type="number" value={range.min} onChange={handleMinChange} />
      <span>à</span>
      <input type="number" value={range.max} onChange={handleMaxChange} />
    </div>
  );
}
