/**
 * Mots pour le jeu du pendu (français).
 * `tier` : 1 = mots courts, prononciation proche de l’écriture (peu de pièges) ;
 *          2 = moyen ; 3 = plus longs ou plus de lettres « muettes » / graphies variées.
 * `hints` : trois indices (mots ou courtes phrases), du plus léger au plus précis.
 */

export type PenduThemeId = 'animaux' | 'corps' | 'objets' | 'nourriture' | 'nature';

export const PENDU_THEME_ORDER: (PenduThemeId | 'tous')[] = [
  'tous',
  'animaux',
  'corps',
  'objets',
  'nourriture',
  'nature',
];

export const PENDU_THEME_LABELS: Record<PenduThemeId | 'tous', string> = {
  tous: 'Tous les mots',
  animaux: 'Animaux',
  corps: 'Corps',
  objets: 'Objets',
  nourriture: 'Nourriture',
  nature: 'Nature',
};

export interface PenduWordEntry {
  w: string;
  theme: PenduThemeId;
  tier: 1 | 2 | 3;
  hints: readonly [string, string, string];
}

/** Raccourci pour les triplets d’indices. */
const h = (a: string, b: string, c: string): readonly [string, string, string] => [a, b, c];

