/**
 * Lettre « de base » pour le jeu : pas de distinction d’accents (é = e = è…).
 * Ligature œ / Œ → o (une seule touche O sur le clavier A–Z).
 */
export function penduNormalizeLetter(char: string): string {
  if (!char) return '';
  let s = char
    .normalize('NFD')
    .replace(/\p{M}/gu, '')
    .toLowerCase();
  // Œ (U+0152) et œ (U+0153) ne se décomposent pas toujours en NFD
  s = s.replace(/\u0153/g, 'o').replace(/\u0152/g, 'o');
  return s;
}

/**
 * Lettres uniques du mot (bases normalisées), pour savoir quand le mot est trouvé.
 */
export function penduWordLetterBases(word: string): Set<string> {
  const set = new Set<string>();
  for (const ch of Array.from(word)) {
    if (/[\s'-]/.test(ch)) continue;
    set.add(penduNormalizeLetter(ch));
  }
  return set;
}

export type PenduGameLevel = 1 | 2 | 3;

export const PENDU_LEVEL_LABELS: Record<PenduGameLevel, string> = {
  1: 'Niveau 1 — mots courts, jusqu’à 10 erreurs',
  2: 'Niveau 2 — mots moyens, jusqu’à 8 erreurs',
  3: 'Niveau 3 — tous les mots, jusqu’à 6 erreurs',
};

/** Erreurs max avant pendu (perdu). */
export function penduMaxErrors(level: PenduGameLevel): number {
  if (level === 1) return 10;
  if (level === 2) return 8;
  return 6;
}

export function getPenduWordPool(
  theme: PenduThemeId | 'tous',
  gameLevel: PenduGameLevel
): PenduWordEntry[] {
  return PENDU_WORDS.filter((entry) => {
    if (theme !== 'tous' && entry.theme !== theme) return false;
    if (gameLevel === 1) {
      return entry.tier === 1 && entry.w.length <= 6;
    }
    if (gameLevel === 2) {
      return entry.tier <= 2 && entry.w.length <= 10;
    }
    return true;
  });
}

export function pickRandomPenduWord(
  pool: PenduWordEntry[],
  excludeNormalized?: string
): PenduWordEntry | null {
  const candidates = excludeNormalized
    ? pool.filter((p) => p.w.toLowerCase() !== excludeNormalized)
    : [...pool];
  if (candidates.length === 0) {
    if (!excludeNormalized || pool.length === 0) return null;
    const i = Math.floor(Math.random() * pool.length);
    return pool[i] ?? null;
  }
  const i = Math.floor(Math.random() * candidates.length);
  return candidates[i] ?? null;
}
