import { useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';

/** Nombre de questions complétées avant retour automatique au menu de l'exercice */
export const EXERCISE_ROUNDS_BEFORE_EXIT = 10;

/**
 * Après N réponses validées (clic sur « Suivant » après un feedback),
 * la prochaine action « Suivant » renvoie vers backPath au lieu d'enchaîner.
 */
export function useExerciseAnswerLimit(backPath: string, maxRounds = EXERCISE_ROUNDS_BEFORE_EXIT) {
  const navigate = useNavigate();
  const completedRoundsRef = useRef(0);

  const wrapNext = useCallback(
    (proceedToNextQuestion: () => void) => {
      completedRoundsRef.current += 1;
      if (completedRoundsRef.current >= maxRounds) {
        navigate(backPath);
        return;
      }
      proceedToNextQuestion();
    },
    [backPath, maxRounds, navigate]
  );

  return { wrapNext };
}
