import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { ShapeRenderer } from './ShapeRenderer';
import { useFormes } from './useFormes';

/**
 * Exercice de géométrie : reconnaître une forme parmi 4 propositions.
 * La forme peut être tournée pour augmenter la difficulté.
 */
export function Formes(): React.ReactElement {
  const { state, isCorrect, selectChoice, next } = useFormes();
  const { wrapNext } = useExerciseAnswerLimit('/maths/geometrie');

  return (
    <ExerciseWrapper title="Reconnaître" backPath="/maths/geometrie">
      <div className="shape-container">
        {/* Forme à identifier */}
        <ShapeRenderer shape={state.shape} color={state.color} rotation={state.rotation} />

        {/* 4 choix de noms */}
        {isCorrect === null ? (
          <div className="shape-choices">
            {state.choices.map((choice) => (
              <button
                key={choice.id}
                className="shape-choice-btn"
                onClick={() => selectChoice(choice.id)}
              >
                {choice.name}
              </button>
            ))}
          </div>
        ) : (
          <Feedback
            isCorrect={isCorrect}
            detail={`C'est un ${state.shape.name}`}
            onNext={() => wrapNext(next)}
          />
        )}
      </div>
    </ExerciseWrapper>
  );
}
