import React, { useState } from 'react';
import { Outlet } from 'react-router-dom';
import { Header as DsfrHeader } from '@codegouvfr/react-dsfr/Header';
import { ScoreDisplay } from './ScoreDisplay';
import { OptionsMenu } from './OptionsMenu';

/**
 * Layout principal avec header DSFR et zone de contenu.
 * Utilisé pour les pages de navigation (accueil, listes de thèmes).
 * Les exercices utilisent ExerciseWrapper à la place.
 */
export function Layout(): React.ReactElement {
  const [optionsOpen, setOptionsOpen] = useState(false);

  return (
    <>
      <DsfrHeader
        brandTop="Edmond"
        homeLinkProps={{ to: '/', title: 'Accueil Edmond' }}
        serviceTagline="Exercices éducatifs CP"
        quickAccessItems={[
          {
            iconId: 'fr-icon-settings-5-line',
            text: 'Options',
            buttonProps: {
              onClick: () => setOptionsOpen(true),
              'aria-label': 'Ouvrir les options',
            },
          },
          {
            iconId: 'fr-icon-star-fill',
            text: <ScoreDisplay />,
            buttonProps: { 'aria-label': 'Score', disabled: true, style: { cursor: 'default' } },
          },
        ]}
      />
      <OptionsMenu
        variant="layout"
        open={optionsOpen}
        onOpenChange={setOptionsOpen}
      />
      <main className="layout-content">
        <Outlet />
      </main>
    </>
  );
}
