import { useState, useCallback } from 'react';
import { generateOperation, Operator, GeneratedOperation } from '../utils/generateOperation';
import { useScore } from './useScore';

/** État retourné par le hook useOperation */
interface UseOperationReturn {
  operation: GeneratedOperation;
  answer: string;
  setAnswer: (value: string) => void;
  isCorrect: boolean | null;
  /** Vérifie la réponse et met à jour le score */
  check: () => void;
  /** Passe à la question suivante */
  next: () => void;
  range: { min: number; max: number };
  /** Met à jour la plage et génère une nouvelle question */
  updateRange: (newRange: { min: number; max: number }) => void;
}

/**
 * Hook partagé par tous les exercices de calcul (+, -, ×, ÷).
 * Gère la génération de questions, la validation et le score.
 */
export function useOperation(
  operator: Operator,
  defaultMin: number,
  defaultMax: number
): UseOperationReturn {
  const { addPoint, removePoint } = useScore();
  const [range, setRange] = useState({ min: defaultMin, max: defaultMax });
  const [operation, setOperation] = useState(() =>
    generateOperation(operator, defaultMin, defaultMax)
  );
  const [answer, setAnswer] = useState('');
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  /** Vérifie si la réponse saisie est correcte */
  const check = useCallback(() => {
    const numAnswer = parseInt(answer, 10);
    if (isNaN(numAnswer)) return;

    const correct = numAnswer === operation.answer;
    setIsCorrect(correct);

    if (correct) addPoint();
    else removePoint();
  }, [answer, operation.answer, addPoint, removePoint]);

  /** Génère une nouvelle question et réinitialise la saisie */
  const next = useCallback(() => {
    setOperation(generateOperation(operator, range.min, range.max));
    setAnswer('');
    setIsCorrect(null);
  }, [operator, range]);

  /** Change la plage de nombres et régénère une question */
  const updateRange = useCallback(
    (newRange: { min: number; max: number }) => {
      setRange(newRange);
      setOperation(generateOperation(operator, newRange.min, newRange.max));
      setAnswer('');
      setIsCorrect(null);
    },
    [operator]
  );

  return { operation, answer, setAnswer, isCorrect, check, next, range, updateRange };
}
