import React, { useState, useCallback } from 'react';
import { ExerciseWrapper } from '../../../../components/ExerciseWrapper';
import { Feedback } from '../../../../components/Feedback';
import { NumPad } from '../../../../components/exercises/NumPad';
import { RangeSelector } from '../../../../components/RangeSelector';
import { useExerciseAnswerLimit } from '../../../../hooks/useExerciseAnswerLimit';
import { useTransformation, type TransformationField } from './useTransformation';
import { TransformationBarInteractive } from './TransformationBarInteractive';

const BACK_PATH = '/maths/calculs';

function EqInput(props: {
  field: TransformationField;
  value: string;
  active: boolean;
  disabled: boolean;
  onChange: (f: TransformationField, v: string) => void;
  onFocus: (f: TransformationField) => void;
  ariaLabel: string;
}): React.ReactElement {
  const { field, value, active, disabled, onChange, onFocus, ariaLabel } = props;
  return (
    <input
      type="text"
      inputMode="numeric"
      autoComplete="off"
      className={`trans-eq-input ${active ? 'trans-bar-input-active' : ''}`}
      value={value}
      disabled={disabled}
      onChange={(e) => onChange(field, e.target.value)}
      onFocus={() => onFocus(field)}
      placeholder="?"
      aria-label={ariaLabel}
    />
  );
}

/**
 * Problèmes de transformation : texte court, diagramme en barres à remplir, calcul écrit en dessous.
 */
export function TransformationProblemes(): React.ReactElement {
  const [numberRange, setNumberRange] = useState({ min: 1, max: 30 });
  const {
    phase,
    current,
    fields,
    setField,
    activeField,
    setActiveField,
    padValue,
    setPadValue,
    feedback,
    validate,
    applyFeedbackNext,
    expected,
    equationOp,
  } = useTransformation(numberRange);
  const { wrapNext } = useExerciseAnswerLimit(BACK_PATH);
  const [incompleteHint, setIncompleteHint] = useState<string | null>(null);

  const stepLabel = phase === 'add' ? 'Addition' : 'Soustraction';
  const stepNum = phase === 'add' ? 1 : 2;

  const onFeedbackNext = (): void => {
    setIncompleteHint(null);
    if (feedback === false) {
      applyFeedbackNext();
      return;
    }
    if (phase === 'add') {
      applyFeedbackNext();
      return;
    }
    wrapNext(applyFeedbackNext);
  };

  const handleValidate = useCallback(() => {
    setIncompleteHint(null);
    const r = validate();
    if (r === 'incomplete') {
      setIncompleteHint('Remplis toutes les cases du diagramme et du calcul.');
    }
  }, [validate]);

  const opSymbol = equationOp === '+' ? '+' : '−';
  const solutionText = `${current.start} ${opSymbol} ${current.delta} = ${expected}`;

  return (
    <ExerciseWrapper title="Transformations" backPath={BACK_PATH}>
      <p className="transformation-intro">
        Lis l’histoire, <strong>remplis les nombres dans le diagramme</strong>, puis{' '}
        <strong>écris le même calcul</strong> en dessous.
      </p>
      <div className="transformation-range-block">
        <span className="transformation-range-label">Nombres utilisés (départ et variation)</span>
        <RangeSelector range={numberRange} onChange={setNumberRange} />
      </div>
      <p className="transformation-step" role="status">
        Étape {stepNum} sur 2 — <strong>{stepLabel}</strong>
      </p>

      <div className="transformation-story-block">
        <p className="transformation-story-text">{current.story}</p>
        <p className="transformation-question">{current.question}</p>
      </div>

      <div className="transformation-workspace">
        <TransformationBarInteractive
          item={current}
          fields={fields}
          activeField={activeField}
          onFieldChange={setField}
          onFieldFocus={setActiveField}
          disabled={feedback !== null}
        />

        <div className="trans-eq-block">
          <p className="trans-eq-heading">Calcul</p>
          <div className="trans-eq-row" role="group" aria-label="Écrire le calcul">
            <EqInput
              field="eq_a"
              value={fields.eq_a}
              active={activeField === 'eq_a'}
              disabled={feedback !== null}
              onChange={setField}
              onFocus={setActiveField}
              ariaLabel="Premier nombre du calcul"
            />
            <span className="trans-eq-op" aria-hidden>
              {opSymbol}
            </span>
            <EqInput
              field="eq_b"
              value={fields.eq_b}
              active={activeField === 'eq_b'}
              disabled={feedback !== null}
              onChange={setField}
              onFocus={setActiveField}
              ariaLabel="Deuxième nombre du calcul"
            />
            <span className="trans-eq-equals" aria-hidden>
              =
            </span>
            <EqInput
              field="eq_result"
              value={fields.eq_result}
              active={activeField === 'eq_result'}
              disabled={feedback !== null}
              onChange={setField}
              onFocus={setActiveField}
              ariaLabel="Résultat du calcul"
            />
          </div>
        </div>
      </div>

      {feedback === null ? (
        <>
          {incompleteHint && <p className="transformation-incomplete-hint">{incompleteHint}</p>}
          <NumPad value={padValue} onChange={setPadValue} onValidate={handleValidate} />
          <button type="button" className="transformation-verify-btn feedback-next" onClick={handleValidate}>
            Vérifier
          </button>
        </>
      ) : (
        <Feedback
          isCorrect={feedback}
          detail={
            feedback
              ? solutionText
              : `Attendu : ${solutionText}. Vérifie que le diagramme et le calcul sont identiques et justes.`
          }
          onNext={onFeedbackNext}
        />
      )}
    </ExerciseWrapper>
  );
}
