import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { ShapeRenderer } from './ShapeRenderer';
import { useTrouveFormes } from './useTrouveFormes';

/**
 * Exercice "Trouve les formes" : plusieurs formes affichées,
 * l'enfant doit cliquer sur toutes celles qui correspondent au nom demandé.
 */
export function TrouveFormes(): React.ReactElement {
  const { targetName, grid, selectedIds, toggleShape, check, isCorrect, next } =
    useTrouveFormes();
  const { wrapNext } = useExerciseAnswerLimit('/maths/geometrie');

  return (
    <ExerciseWrapper title="Trouve les formes" backPath="/maths/geometrie">
      {/* Consigne */}
      <div style={{ fontSize: 22, fontWeight: 700, textAlign: 'center' }}>
        Trouve tous les <span style={{ color: '#4A90D9' }}>{targetName}s</span> !
      </div>

      {/* Grille de 8 formes (4 colonnes × 2 lignes) */}
      <div className="trouve-grid">
        {grid.map((item) => {
          const isSelected = selectedIds.has(item.uid);
          return (
            <div
              key={item.uid}
              className={`trouve-shape ${isSelected ? 'trouve-shape-selected' : ''}`}
              onClick={() => toggleShape(item.uid)}
            >
              <ShapeRenderer shape={item.shape} color={item.color} rotation={item.rotation} />
            </div>
          );
        })}
      </div>

      {/* Bouton vérifier ou feedback */}
      {isCorrect === null ? (
        <button
          className="feedback-next"
          onClick={check}
          disabled={selectedIds.size === 0}
        >
          Vérifier
        </button>
      ) : (
        <Feedback isCorrect={isCorrect} onNext={() => wrapNext(next)} />
      )}
    </ExerciseWrapper>
  );
}
