import React from 'react';
import { ExerciseWrapper } from '../../../components/ExerciseWrapper';
import { RangeSelector } from '../../../components/RangeSelector';
import { Feedback } from '../../../components/Feedback';
import { useExerciseAnswerLimit } from '../../../hooks/useExerciseAnswerLimit';
import { useComparaison } from './useComparaison';

const SIGNS = ['<', '>', '='];

/**
 * Exercice de comparaison : deux nombres affichés, l'enfant choisit <, > ou =.
 */
export function SuperieurInferieur(): React.ReactElement {
  const { state, isCorrect, selectSign, next, range, updateRange } = useComparaison();
  const { wrapNext } = useExerciseAnswerLimit('/maths');

  return (
    <ExerciseWrapper title="Comparaison" backPath="/maths">
      <RangeSelector range={range} onChange={updateRange} />

      {/* Les deux nombres côte à côte */}
      <div className="comparison-numbers">
        <span>{state.a}</span>
        <span style={{ color: '#ccc' }}>?</span>
        <span>{state.b}</span>
      </div>

      {/* Boutons de choix du signe */}
      {isCorrect === null ? (
        <div className="comparison-signs">
          {SIGNS.map((sign) => (
            <button key={sign} className="comparison-btn" onClick={() => selectSign(sign)}>
              {sign}
            </button>
          ))}
        </div>
      ) : (
        <Feedback
          isCorrect={isCorrect}
          detail={`${state.a} ${state.answer} ${state.b}`}
          onNext={() => wrapNext(next)}
        />
      )}
    </ExerciseWrapper>
  );
}
